import React, { useState, useEffect, useRef } from "react";

async function osLoad(key, fallback) { try { const r = await window.storage.get("gp-" + key); if (r && r.value) return JSON.parse(r.value); return fallback; } catch (e) { return fallback; } }
async function osSave(key, value) { try { await window.storage.set("gp-" + key, JSON.stringify(value)); } catch (e) { console.error("Save failed:", e); } }

const C = { bg: "#ffffff", bgS: "#f7f7f5", tx: "#37352f", txS: "#787774", txT: "#b4b4b0", bdr: "#e9e9e7", bdrH: "#d3d3d0", blue: "#2eaadc", blueBg: "#d3e5ef", red: "#e03e3e", redBg: "#fbe4e4", green: "#0f7b6c", greenBg: "#dbeddb", yellow: "#dfab01", yellowBg: "#fdecc8", purple: "#6940a5", purpleBg: "#e8deee", orange: "#d9730d", orangeBg: "#fadec9", pink: "#ad1a72", pinkBg: "#f4dfeb", coral: "#D85A30", coralBg: "#FAECE7", teal: "#0F6E56", tealBg: "#E1F5EE" };
