const Tag = ({ children, color }) => { const m = { blue: { bg: C.blueBg, c: C.blue }, green: { bg: C.greenBg, c: C.green }, red: { bg: C.redBg, c: C.red }, yellow: { bg: C.yellowBg, c: "#856d0a" }, purple: { bg: C.purpleBg, c: C.purple }, orange: { bg: C.orangeBg, c: C.orange }, pink: { bg: C.pinkBg, c: C.pink }, coral: { bg: C.coralBg, c: C.coral }, teal: { bg: C.tealBg, c: C.teal } }; const s = m[color] || { bg: C.bgS, c: C.tx }; return <span style={{ display: "inline-flex", padding: "2px 8px", borderRadius: 3, fontSize: 11, fontFamily: F.sans, fontWeight: 500, background: s.bg, color: s.c, lineHeight: "20px", whiteSpace: "nowrap" }}>{children}</span>; };
const Pill = ({ children, color, bg }) => <span style={{ fontSize: 11, fontWeight: 500, padding: "2px 8px", borderRadius: 4, background: bg || C.bgS, color: color || C.tx, fontFamily: F.sans }}>{children}</span>;
const CONF_LEVELS = [{ key: "no_idea", label: "no idea", bg: C.bgS, color: C.txT }, { key: "learning", label: "learning", bg: C.yellowBg, color: "#856d0a" }, { key: "learned", label: "learned", bg: C.blueBg, color: "#185FA5" }, { key: "applied", label: "applied", bg: C.purpleBg, color: C.purple }, { key: "confident", label: "confident", bg: C.greenBg, color: C.green }];
const ConfChip = ({ level, onClick }) => { const conf = CONF_LEVELS.find(c => c.key === level) || CONF_LEVELS[0]; return <span onClick={onClick} style={{ fontSize: 10, fontWeight: 500, padding: "2px 10px", borderRadius: 10, background: conf.bg, color: conf.color, whiteSpace: "nowrap", cursor: "pointer", userSelect: "none", fontFamily: F.sans, flexShrink: 0 }}>{conf.label}</span>; };
const Check = ({ checked, onClick }) => { if (checked) return <div onClick={onClick} style={{ width: 13, height: 13, borderRadius: 3, background: C.green, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", flexShrink: 0 }}><svg width="7" height="5" viewBox="0 0 8 6" fill="none"><path d="M1 3L3 5L7 1" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" /></svg></div>; return <div onClick={onClick} style={{ width: 13, height: 13, borderRadius: 3, border: `1.5px solid ${C.bdrH}`, cursor: "pointer", flexShrink: 0 }} />; };
const BUILD_LEVELS = [{ key: "none", label: "none", bg: C.bgS, color: C.txT }, { key: "building", label: "building", bg: C.yellowBg, color: "#856d0a" }, { key: "testing", label: "testing", bg: C.blueBg, color: "#185FA5" }, { key: "fixing", label: "fixing", bg: C.orangeBg, color: C.orange }, { key: "shipped", label: "shipped", bg: C.greenBg, color: C.green }, { key: "update", label: "updated", bg: C.purpleBg, color: C.purple }];
const BuildChip = ({ level, onClick }) => { const s = BUILD_LEVELS.find(c => c.key === level) || BUILD_LEVELS[0]; return <span onClick={onClick} style={{ fontSize: 10, fontWeight: 500, padding: "2px 10px", borderRadius: 10, background: s.bg, color: s.color, whiteSpace: "nowrap", cursor: "pointer", userSelect: "none", fontFamily: F.sans, flexShrink: 0 }}>{s.label}</span>; };

