// ── HOWTO_GUIDES (complete, unchanged from original) ──
const HOWTO_GUIDES = [
  { id: "deploy", title: "How to deploy Evalynn OS to Vercel + Supabase", context: "Right now your app lives inside Claude's chat window. If the chat breaks or you start a new one, your data could disappear. This guide gives your app a permanent home on the internet - like moving from renting a room to owning a house.", steps: [{ step: "1. Create a place for your code (GitHub)", what: "> Go to **github.com/new**\n> Name it **eva-os**, choose **Public**, do NOT check **Add a README file**\n> Click **Create repository** - you'll see a setup page, leave it open", why: "GitHub is like Google Drive but for code. It saves every version of your files. When you change something, the old version is still there. Vercel reads your code from GitHub to build your website." }, { step: "2. Create a database (Supabase)", what: "> Go to **supabase.com**, sign in or sign up free\n> Click **New Project**, name it **Eva OS**, region **Asia-Pacific**\n> Click **Generate a password** and SAVE it somewhere\n> Keep **Enable Data API** checked, leave **Enable automatic RLS** unchecked\n> Click **Create new project** - wait about 1 minute", why: "Supabase is a free online database. Think of it as a Google Sheet that your app can read and write to automatically - but faster and more reliable. Supabase makes your data permanent." }, { step: "3. Create your table (SQL)", what: "> In Supabase left sidebar, click the **SQL Editor** icon\n> Delete anything in the editor, paste:\n\nCREATE TABLE IF NOT EXISTS kv_store (\n  key TEXT PRIMARY KEY,\n  value TEXT NOT NULL,\n  updated_at TIMESTAMPTZ DEFAULT NOW()\n);\n\nALTER TABLE kv_store ENABLE ROW LEVEL SECURITY;\n\nCREATE POLICY \"Allow all\" ON kv_store\n  FOR ALL USING (true) WITH CHECK (true);\n\n> Click **Run**. **Success. No rows returned** = correct", why: "SQL is the language databases understand. This creates one table called kv_store. 'No rows returned' means it built the table but didn't add data yet." }, { step: "4. Get your connection keys (API Keys)", what: "> In Supabase sidebar, click **Settings** -> **API Keys**\n> Copy the **Publishable key** - label it ANON KEY\n> Go to dashboard, copy **Project URL** - label it PROJECT URL\n> Save both somewhere safe", why: "Your app needs WHERE the database is (URL) and a PASSWORD (publishable key). Like a phone number + PIN code." }, { step: "5. Upload your code to GitHub (Terminal)", what: "> Open **Terminal**\n> cd ~/Downloads/Eva\\ OS/deploy/evalynn-os\n> npm install\n> git init\n> git add .\n> git commit -m \"Initial deploy\"\n> git remote add origin **https://github.com/evajept/eva-os.git**\n> git branch -M main\n> git push -u origin main\n> **Username**: your GitHub username\n> **Password**: paste **Personal Access Token**", why: "Terminal is how developers control their computer with text commands. Each command does one thing. The Personal Access Token is GitHub's security - regular passwords were turned off in 2021." }, { step: "6. Put your app online (Vercel)", what: "> Go to **vercel.com**, sign in\n> Click **Add New** -> **Project**, find **eva-os**, click **Import**\n> Framework Preset: **Vite**\n> Add Environment Variables:\n  **VITE_SUPABASE_URL** / your Project URL\n  **VITE_SUPABASE_ANON_KEY** / your publishable key\n> Click **Deploy**", why: "Vercel is a free website host. Environment variables connect your app to Supabase but stay hidden. The VITE_ prefix is required." }, { step: "7. You're live!", what: "> Open your app URL (like **eva-os-nine.vercel.app**)\n> Future updates - just 3 commands:\ngit add .\ngit commit -m \"what you changed\"\ngit push\n\nVercel auto-rebuilds in ~30 seconds.", why: "This is your permanent workflow. Edit code, push to GitHub, Vercel auto-deploys." }], skills: ["Deployment", "Git", "Supabase", "Vercel", "Terminal"] },
  { id: "api-proxy", title: "How to set up Claude API on your deployed app", context: "The Health Officer needs to call Claude's API. On your own website, you need a proxy - a middleman that adds your secret API key before forwarding the request to Anthropic.", steps: [{ step: "1. Get an Anthropic API key", what: "> Go to **console.anthropic.com** -> **API Keys** -> **Create Key**\n> Copy the key (starts with **sk-ant-...**)\n> Never share it or put it in your code", why: "The API key tells Anthropic who is making the request and charges your account." }, { step: "2. Add the key to Vercel", what: "> **vercel.com** -> eva-os -> **Settings** -> **Environment Variables**\n> Key: **ANTHROPIC_API_KEY** / Value: your sk-ant-... key\n> Click **Save**", why: "Environment variables on Vercel are secret - only visible to server-side code." }, { step: "3. Create the proxy file", what: "> On GitHub, **Add file** -> **Create new file**\n> Filename: **api/analyze.js**\n> Paste the proxy code that forwards to Anthropic\n> Click **Commit changes**", why: "This serverless function runs on Vercel's server. It adds your API key and forwards to Anthropic. The browser never sees the key." }, { step: "4. Update App.jsx to use the proxy", what: "> Change fetch URL from:\nfetch(\"https://api.anthropic.com/v1/messages\"\n> To:\nfetch(\"/api/analyze\"", why: "The browser can't call Anthropic directly because of CORS. /api/analyze goes to YOUR server first." }, { step: "5. Update vercel.json for routing", what: "> Replace vercel.json content with rewrites for /api/* and catch-all", why: "This tells Vercel: /api/* goes to serverless functions, everything else goes to the app." }, { step: "6. Test it", what: "> Wait 30 seconds for redeploy\n> Go to **Health Officer** tab -> click **Run health analysis**\n> You should see score cards, patterns, wins, and flags", why: "Full chain: browser -> /api/analyze -> Anthropic -> JSON response -> your UI." }], skills: ["API", "Serverless Functions", "Security", "CORS"] },
  { id: "troubleshoot", title: "Troubleshooting - things that went wrong and how to fix them", context: "Real problems from the first Evalynn OS deployment. If you hit any of these again, the fix is here.", steps: [{ step: "Terminal: 'npm: command not found'", what: "Node.js not installed.\n> Install Homebrew:\n/bin/bash -c \"$(curl -fsSL https://raw.githubusercontent.com/Homebrew/install/HEAD/install.sh)\"\n> Add to path:\necho 'eval \"$(/opt/homebrew/bin/brew shellenv)\"' >> ~/.zprofile\neval \"$(/opt/homebrew/bin/brew shellenv)\"\n> Install Node:\nbrew install node", why: "Mac doesn't come with Node.js. Homebrew is the App Store for Terminal tools." }, { step: "Terminal: 'brew: command not found'", what: "> Run:\necho 'eval \"$(/opt/homebrew/bin/brew shellenv)\"' >> ~/.zprofile\neval \"$(/opt/homebrew/bin/brew shellenv)\"", why: "Homebrew installed but Terminal doesn't know where to find it." }, { step: "Terminal: Homebrew install aborted", what: "> Just run the install command again. Only press Enter when asked.", why: "Any key other than Enter cancels the installer." }, { step: "Terminal: password doesn't show when typing", what: "> Just type your password and press Enter. This is normal - no dots or stars appear.", why: "Security feature. Even the character count is hidden." }, { step: "Git: 'Password authentication is not supported'", what: "> Go to github.com/settings/tokens\n> Generate new token (classic), check 'repo'\n> Use this token as 'password' for git push", why: "GitHub stopped regular passwords in 2021. Tokens are safer - limited scope, revokable." }, { step: "Git: pasted token as command", what: "> Run git push again. Wait for Username prompt first, then Password prompt.", why: "Terminal processes one input at a time. Username and password are separate prompts." }, { step: "Git: 'remote origin already exists'", what: "> git remote set-url origin https://github.com/evajept/eva-os.git", why: "Use set-url to update instead of add." }, { step: "Terminal: folder path errors", what: "> Use backslash before spaces:\ncd ~/Downloads/Eva\\ OS/deploy/evalynn-os\n> Or use quotes:\ncd \"~/Downloads/Eva OS/deploy/evalynn-os\"", why: "Terminal uses spaces to separate commands. Backslash or quotes tell it 'this space is part of the name.'" }, { step: "SQL Editor: typed filename instead of SQL code", what: "> Paste the actual SQL code, not the filename. Select all, delete, paste the CREATE TABLE code.", why: "The SQL Editor runs commands directly - it's not a file uploader." }, { step: "Vercel: blank page after deploy", what: "> Right-click -> Inspect -> Console tab. Check errors:\n> 'React is not defined' -> add import React at top\n> 'MIME type' -> check Framework Preset is Vite", why: "Standalone Vite app needs explicit React import unlike Claude artifacts." }, { step: "Vercel: Environment Variables", what: "> Key: VITE_SUPABASE_URL / Value: your Supabase URL\n> Key: VITE_SUPABASE_ANON_KEY / Value: your publishable key\n> VITE_ prefix is required", why: "Env vars live on the server, hidden from GitHub. Vercel injects them at build time." }], skills: ["Terminal", "Git", "Debugging"] },
  { id: "api-proxy-2", title: "How to set up Claude API proxy on Vercel", context: "Claude API can't be called from browser (CORS). You need a serverless function as a middleman.", steps: [{ step: "1. Get an Anthropic API key", what: "> **console.anthropic.com** -> **API Keys** -> **Create Key**\n> Copy it (starts with **sk-ant-...**)", why: "This key lets your app use Claude. It goes in Vercel env vars, not in code." }, { step: "2. Add the key to Vercel", what: "> vercel.com -> eva-os -> Settings -> Environment Variables\n> Key: **ANTHROPIC_API_KEY** / Value: your key\n> Save", why: "Only visible to server-side code. Never reaches the browser." }, { step: "3. Create the serverless function", what: "> On GitHub, create **api/analyze.js**\n> Paste the proxy code\n> Commit", why: "Vercel turns any .js in /api into a serverless function." }, { step: "4. Update App.jsx to use the proxy", what: "> Change fetch from api.anthropic.com to /api/analyze", why: "Routes through your Vercel server which adds the API key." }, { step: "5. Test it", what: "> Wait 30 seconds -> Health Officer -> Run health analysis\n> If 'Failed to fetch' - check API key in Vercel settings", why: "Full chain: browser -> your Vercel server -> Anthropic -> response back." }], skills: ["API", "Serverless", "Security", "Vercel"] },
  { id: "first-api-call", title: "How to make your first Claude API call", context: "The core pattern: send data + instructions, get back structured response.", steps: [{ step: "1. Collect the data", what: "Read habit data from storage. Loop through last 7 days. Build object:\n{ \"Day 20\": { \"Sleep\": \"6\", \"Work\": \"done\", \"Berberine\": \"skipped\" } }", why: "Clean data format = better analysis. Convert internal keys to readable labels." }, { step: "2. Write the prompt", what: "Three parts:\n> **Role**: 'You are Evalynn's Health Officer'\n> **Data**: habit data as JSON\n> **Output format**: 'Respond ONLY with JSON: { overall_score, wins, flags... }'", why: "Role sets personality. Output format is crucial - structured output lets you parse and display." }, { step: "3. Make the fetch call", what: "fetch('/api/analyze', {\n  method: 'POST',\n  body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 1000, messages: [...] })\n})", why: "Standard HTTP request. Same format as Anthropic API docs." }, { step: "4. Parse the response", what: "const text = result.content.find(b => b.type === 'text')?.text\nconst parsed = JSON.parse(text)", why: "API returns content blocks. Parse JSON string into usable object." }, { step: "5. Handle errors", what: "> **Network error** - 'Failed to fetch'\n> **Bad JSON** - strip backticks\n> **API error** - 401/429/500\n\nRetry up to 3 times with increasing delays (exponential backoff).", why: "APIs fail. Production code always handles errors. Retry with backoff is industry standard." }], skills: ["API", "Prompt Engineering", "Error Handling", "JSON"] },
  { id: "big-picture", title: "How it all connects - the big picture", context: "What actually happens when you click 'Run health analysis'? The full flow.", steps: [{ step: "The three places your code runs", what: "**Your browser** - React app. What you see and click.\n**Vercel server** - proxy. Forwards requests with your API key.\n**Anthropic servers** - Claude's brain. Analyzes and responds.", why: "Browser can't talk to Anthropic directly (CORS). It talks to YOUR server first." }, { step: "Step 1-2: Saving habits to Supabase", what: "> You click -> React updates state -> osSave() -> Supabase stores it\n\nData format: '20_sleep': '6', '15_work': true", why: "Every click saves immediately. All March data under one key." }, { step: "Step 3-5: The API call chain", what: "> loadAllData() reads from Supabase\n> POST to /api/analyze\n> Vercel adds API key, forwards to Anthropic\n> Claude generates JSON\n> Response flows back\n\nRetry: 1s, 2s, 3s delays on failure.", why: "Structured output - you tell Claude the exact JSON shape. Then JSON.parse() it." }, { step: "Step 6: Tool use - trends calculated locally", what: "BEFORE the API call, your browser calculates:\n> Sleep average this week vs last\n> Supplement compliance %\n> Work intensity %", why: "JavaScript calculates faster and cheaper. AI interprets the patterns." }, { step: "Step 7: Proactive alerts", what: "> IF berberine < 50% AND glucose > 100 -> DANGER\n> IF sleep < 6 hours -> DANGER\n> IF water < 1.5L -> WARNING\n\nThese fire instantly, before the API responds.", why: "Not everything needs AI. Rules are instant, free, and reliable." }, { step: "Step 8: Cross-agent context", what: "Work intensity sent alongside health data:\n> career_context: 'Work intensity: 81% (last week: 75%)'", why: "One agent reads another agent's data. Health + work = burnout detection." }, { step: "Step 9: Weekly summary", what: "Claude returns 'weekly_summary' and 'trend_insight' fields.\nDisplayed in blue box at top of results.", why: "The Health Officer's 'report'. Connects dots across all data." }, { step: "The full flow in one sentence", what: "Habit click -> Supabase -> Run Analysis -> read data, calc trends, check alerts, package context -> Vercel proxy -> Claude -> JSON response -> UI with scores, arrows, alerts, report.", why: "9 learning steps collapsed into one pipeline. Each step transforms data for the next." }], skills: ["Architecture", "Data Flow", "Mental Model"] },
];

// ── Plan tab (renamed from Learning plan) ──
function PlanTab({ startDate, setStartDate, data, setData }) {
  const getDateRange = (phIdx) => { if (!startDate) return null; const sd = new Date(startDate); const ws = new Date(sd); ws.setDate(ws.getDate() + PHASE_WEEKS[phIdx] * 7); const we = new Date(ws); we.setDate(we.getDate() + 20); const fmt = (d) => d.toLocaleDateString("en-US", { month: "short", day: "numeric" }); return fmt(ws) + " - " + fmt(we); };
  const getActions = (ph) => data[ph.id]?.actions || ph.actions;
  const getSkills = (ph) => data[ph.id]?.skills || ph.skills;
  const updAction = (phId, aId) => { const ph = GP_PHASES.find(p => p.id === phId); const cur = data[phId]?.actions || ph.actions; setData(p => ({ ...p, [phId]: { ...p[phId], actions: cur.map(a => a.id === aId ? { ...a, done: !a.done } : a) } })); };
  const cycleConf = (phId, sId) => { const ph = GP_PHASES.find(p => p.id === phId); const cur = data[phId]?.skills || ph.skills; setData(p => ({ ...p, [phId]: { ...p[phId], skills: cur.map(s => { if (s.id !== sId) return s; const idx = CONF_LEVELS.findIndex(c => c.key === s.conf); return { ...s, conf: CONF_LEVELS[(idx + 1) % CONF_LEVELS.length].key }; }) } })); };
  const totalA = GP_PHASES.reduce((s, ph) => s + getActions(ph).length, 0);
  const doneA = GP_PHASES.reduce((s, ph) => s + getActions(ph).filter(a => a.done).length, 0);
  const totalS = GP_PHASES.reduce((s, ph) => s + getSkills(ph).length, 0);
  const confS = GP_PHASES.reduce((s, ph) => s + getSkills(ph).filter(a => a.conf === "confident").length, 0);
  return (<div>
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginBottom: 20 }}>{[{ l: "Actions", v: `${doneA}/${totalA} done`, c: doneA === totalA ? C.green : C.orange }, { l: "Skills confident", v: `${confS}/${totalS}`, c: confS === totalS ? C.green : C.txS }, { l: "Portfolio", v: "App + README + Demo video", c: C.txS }].map((g, i) => (<div key={i} style={{ background: C.bgS, borderRadius: 4, padding: "10px 12px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", marginBottom: 3 }}>{g.l}</div><div style={{ fontSize: 13, fontWeight: 500, color: g.c }}>{g.v}</div></div>))}</div>
    <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 20 }}><div style={{ display: "flex", alignItems: "center", gap: 8 }}><span style={{ fontSize: 11, color: C.txS }}>Start date</span><input type="date" value={startDate || ""} onChange={e => setStartDate(e.target.value)} style={{ border: `1px solid ${C.bdr}`, borderRadius: 3, padding: "4px 8px", fontFamily: F.sans, fontSize: 12, color: C.tx, background: "transparent", outline: "none" }} /></div></div>
    <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 16, flexWrap: "wrap" }}><span style={{ fontSize: 11, color: C.txT }}>Skill confidence (click to cycle):</span>{CONF_LEVELS.map(c => <span key={c.key} style={{ fontSize: 10, fontWeight: 500, padding: "2px 8px", borderRadius: 10, background: c.bg, color: c.color, fontFamily: F.sans }}>{c.label}</span>)}</div>
    {GP_PHASES.map((ph, phIdx) => { const acts = getActions(ph); const skls = getSkills(ph); const dr = getDateRange(phIdx); return (<div key={ph.id}><div style={{ background: C.bgS, padding: "12px 16px", borderTop: phIdx === 0 ? `1px solid ${C.bdr}` : "none", borderBottom: `1px solid ${C.bdr}` }}><div style={{ display: "flex", alignItems: "baseline", gap: 8, flexWrap: "wrap", marginBottom: 4 }}><Tag color={ph.color}>{ph.ph}</Tag><span style={{ fontFamily: F.sans, fontSize: 14, fontWeight: 600, color: C.tx }}>{ph.title}</span><span style={{ fontFamily: F.mono, fontSize: 12, color: C.txS }}>{ph.wk}{dr && <span style={{ marginLeft: 6, fontSize: 11, color: C.txT }}>{dr}</span>}</span></div><div style={{ display: "flex", gap: 5, flexWrap: "wrap", marginBottom: 4 }}>{ph.courses.map((c, i) => <Pill key={i} color="#185FA5" bg={C.blueBg}>{c}</Pill>)}{ph.dom.map((d, i) => <Pill key={"d" + i} color={C.purple} bg={C.purpleBg}>{d}</Pill>)}</div><div style={{ fontSize: 11, color: C.txS }}>Milestone: {ph.ms}</div></div><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 0 }}><div style={{ padding: "8px 16px 4px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", padding: "4px 0 6px" }}>Actions</div>{acts.map(a => <div key={a.id} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0", borderBottom: `1px solid ${C.bdr}` }}><Check checked={a.done} onClick={() => updAction(ph.id, a.id)} /><span style={{ fontSize: 13, fontFamily: F.sans, color: a.done ? C.txT : C.tx, textDecoration: a.done ? "line-through" : "none", lineHeight: 1.45 }}>{a.text}</span></div>)}</div><div style={{ padding: "8px 16px 4px" }}><div style={{ display: "flex", justifyContent: "space-between", padding: "4px 0 6px" }}><span style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em" }}>Skills to build</span><span style={{ fontSize: 10, color: C.txT }}>confidence</span></div>{skls.map(s => <div key={s.id} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, padding: "6px 0", borderBottom: `1px solid ${C.bdr}` }}><span style={{ fontSize: 13, fontFamily: F.sans, color: C.tx, lineHeight: 1.45 }}>{s.text}</span><ConfChip level={s.conf} onClick={() => cycleConf(ph.id, s.id)} /></div>)}</div></div>{phIdx < GP_PHASES.length - 1 && <div style={{ height: 20 }} />}</div>); })}
  </div>);
}

// ── Product tab (moved to first, renamed from Product blueprint) ──
function ProductTab({ agentData, setAgentData, data, setData }) {
  const allSkills = GP_PHASES.flatMap(ph => { const saved = data[ph.id]?.skills || ph.skills; return saved.map(s => ({ ...s, phaseId: ph.id, phaseColor: ph.color })); });
  const getSkillById = sId => allSkills.find(s => s.id === sId);
  const cycleSkillConf = (phId, sId) => { const ph = GP_PHASES.find(p => p.id === phId); const cur = data[phId]?.skills || ph.skills; setData(p => ({ ...p, [phId]: { ...p[phId], skills: cur.map(s => { if (s.id !== sId) return s; const idx = CONF_LEVELS.findIndex(c => c.key === s.conf); return { ...s, conf: CONF_LEVELS[(idx + 1) % CONF_LEVELS.length].key }; }) } })); };
  const cycleBuild = (agentId, itemId) => { const cur = agentData[agentId] || {}; const items = cur.items || {}; const level = items[itemId] || "none"; const idx = BUILD_LEVELS.findIndex(b => b.key === level); const next = BUILD_LEVELS[(idx + 1) % BUILD_LEVELS.length].key; setAgentData(p => ({ ...p, [agentId]: { ...p[agentId], items: { ...(p[agentId]?.items || {}), [itemId]: next } } })); };
  const getBuildLevel = (agentId, itemId) => (agentData[agentId]?.items || {})[itemId] || "none";
  return (<div>
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginBottom: 20 }}>{[{ l: "Agents", v: "7", c: C.purple }, { l: "Data tools", v: "building", c: C.orange }, { l: "Daily input goal", v: "< 2 min total", c: C.txS }].map((g, i) => <div key={i} style={{ background: C.bgS, borderRadius: 4, padding: "10px 12px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", marginBottom: 3 }}>{g.l}</div><div style={{ fontSize: 13, fontWeight: 500, color: g.c }}>{g.v}</div></div>)}</div>
    <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 16, flexWrap: "wrap" }}><span style={{ fontSize: 11, color: C.txT }}>Build status (click to cycle):</span>{BUILD_LEVELS.map(c => <span key={c.key} style={{ fontSize: 10, fontWeight: 500, padding: "2px 8px", borderRadius: 10, background: c.bg, color: c.color, fontFamily: F.sans }}>{c.label}</span>)}</div>
    {AGENTS.map(agent => { const resolvedSkills = (agent.skillRefs || []).map(getSkillById).filter(Boolean); return (<div key={agent.id}>
      <div style={{ background: C.bgS, padding: "12px 16px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ display: "flex", alignItems: "baseline", gap: 8, flexWrap: "wrap", marginBottom: 4 }}><Tag color={agent.tagColor}>{agent.name}</Tag><span style={{ fontSize: 12, color: C.txS }}>{agent.mode}</span></div><div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>{agent.roles.map((r, i) => <Pill key={i} color={C.txS} bg={C.bgS}>{r}</Pill>)}</div><div style={{ display: "flex", gap: 5, flexWrap: "wrap", marginTop: 4 }}>{agent.courses.map((c, i) => <Pill key={"c" + i} color="#185FA5" bg={C.blueBg}>{c}</Pill>)}</div><div style={{ display: "flex", gap: 5, flexWrap: "wrap", marginTop: 4 }}>{agent.domains.map((d, i) => <Pill key={"d" + i} color={C.purple} bg={C.purpleBg}>{d}</Pill>)}</div></div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr" }}><div style={{ padding: "8px 16px 4px" }}><div style={{ display: "flex", justifyContent: "space-between", padding: "4px 0 6px" }}><span style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em" }}>Data to build</span><span style={{ fontSize: 10, color: C.txT }}>status</span></div>{agent.dataMissing.map(d => <div key={d.id} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, padding: "6px 0", borderBottom: `1px solid ${C.bdr}` }}><span style={{ fontSize: 13, fontFamily: F.sans, color: C.tx, lineHeight: 1.45 }}>{d.text}</span><BuildChip level={getBuildLevel(agent.id, d.id)} onClick={() => cycleBuild(agent.id, d.id)} /></div>)}<div style={{ display: "flex", justifyContent: "space-between", padding: "8px 0 6px", marginTop: 4 }}><span style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em" }}>Data exists</span><span style={{ fontSize: 10, color: C.txT }}>status</span></div>{agent.dataExists.map((d, i) => <div key={"e" + i} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, padding: "6px 0", borderBottom: `1px solid ${C.bdr}` }}><span style={{ fontSize: 13, fontFamily: F.sans, color: C.txS, lineHeight: 1.45 }}>{d}</span><BuildChip level={getBuildLevel(agent.id, "e_" + i)} onClick={() => cycleBuild(agent.id, "e_" + i)} /></div>)}</div><div style={{ padding: "8px 16px 4px" }}><div style={{ display: "flex", justifyContent: "space-between", padding: "4px 0 6px" }}><span style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em" }}>Skills needed</span><span style={{ fontSize: 10, color: C.txT }}>confidence</span></div>{resolvedSkills.map(s => <div key={s.id} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, padding: "6px 0", borderBottom: `1px solid ${C.bdr}` }}><span style={{ fontSize: 13, fontFamily: F.sans, color: C.tx, lineHeight: 1.45 }}>{s.text}</span><ConfChip level={s.conf} onClick={() => cycleSkillConf(s.phaseId, s.id)} /></div>)}</div></div>
      {agent.steps.length > 0 && (() => { const getStepConf = sid => (agentData[agent.id]?.stepConf || {})[sid] || "no_idea"; const cycleStepConf = sid => { const cur = getStepConf(sid); const idx = CONF_LEVELS.findIndex(c => c.key === cur); const next = CONF_LEVELS[(idx + 1) % CONF_LEVELS.length].key; setAgentData(p => ({ ...p, [agent.id]: { ...p[agent.id], stepConf: { ...(p[agent.id]?.stepConf || {}), [sid]: next } } })); }; const doneSteps = agent.steps.filter(s => getStepConf(s.id) === "confident").length; return (<div style={{ borderBottom: `1px solid ${C.bdr}` }}><div style={{ padding: "8px 16px", display: "flex", alignItems: "center", gap: 8, background: C.bgS }}><span style={{ fontSize: 11, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em" }}>Learning journey</span><span style={{ fontSize: 11, color: doneSteps === agent.steps.length ? C.green : C.txT, marginLeft: "auto" }}>{doneSteps}/{agent.steps.length}</span></div><div style={{ padding: "0 16px 8px" }}>{agent.steps.map((step, si) => <div key={step.id} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0", borderBottom: `1px solid ${C.bdr}` }}><span style={{ fontSize: 11, fontWeight: 600, color: C.txT, minWidth: 18, textAlign: "right", fontFamily: F.mono, flexShrink: 0 }}>{si + 1}.</span><span style={{ fontSize: 13, fontFamily: F.sans, color: C.tx, flex: 1, lineHeight: 1.45 }}>{step.text}</span><ConfChip level={getStepConf(step.id)} onClick={() => cycleStepConf(step.id)} /></div>)}</div></div>); })()}
      <div style={{ padding: "8px 16px 12px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ fontSize: 12, color: C.txS, fontStyle: "italic", lineHeight: 1.5 }}>"{agent.voice}"</div></div>
      <div style={{ height: 12 }} />
    </div>); })}
  </div>);
}

// ── CCA tab (restructured with courses + sub-topics + progress + Reference merged) ──
function CCATab({ ccaData, setCcaData }) {
  const [openCourse, setOpenCourse] = useState(null);
  const topicDone = ccaData.topicDone || {};
  const toggleTopic = (courseId, topicIdx) => { const key = courseId + "_" + topicIdx; setCcaData(p => ({ ...p, topicDone: { ...p.topicDone, [key]: !topicDone[key] } })); };
  const prep = ccaData.prep || CCA_PREP;
  const togglePrep = id => setCcaData(p => ({ ...p, prep: (p.prep || CCA_PREP).map(pp => pp.id === id ? { ...pp, done: !pp.done } : pp) }));
  const donePrep = prep.filter(p => p.done).length;

  const totalTopics = CCA_COURSES.reduce((s, c) => s + c.topics.length, 0);
  const doneTopics = CCA_COURSES.reduce((s, c) => s + c.topics.filter((_, i) => topicDone[c.id + "_" + i]).length, 0);
  const totalPct = totalTopics > 0 ? Math.round((doneTopics / totalTopics) * 100) : 0;

  const lnk = { fontSize: 13, color: C.blue, textDecoration: "none", fontFamily: F.sans };

  // Reference section helpers
  const agentSkillMap = {};
  AGENTS.forEach(a => { (a.skillRefs || []).forEach(sId => { if (!agentSkillMap[sId]) agentSkillMap[sId] = []; agentSkillMap[sId].push(a.name); }); });
  const allSkillsFromPhases = GP_PHASES.flatMap(ph => ph.skills.map(s => s.id));
  const coveredByAgents = new Set(AGENTS.flatMap(a => a.skillRefs || []));
  const uncovered = allSkillsFromPhases.filter(id => !coveredByAgents.has(id));

  return (<div>
    {/* Exam stats */}
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr", gap: 10, marginBottom: 20 }}>{[{ l: "Exam", v: "CCA-F", c: C.purple }, { l: "Questions", v: "60 proctored", c: C.txS }, { l: "Pass score", v: "720 / 1,000", c: C.green }, { l: "Cost", v: "$99 per attempt", c: C.txS }].map((g, i) => <div key={i} style={{ background: C.bgS, borderRadius: 4, padding: "10px 12px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", marginBottom: 3 }}>{g.l}</div><div style={{ fontSize: 13, fontWeight: 500, color: g.c }}>{g.v}</div></div>)}</div>

    {/* Total progress bar */}
    <div style={{ background: C.bgS, borderRadius: 4, padding: "12px 16px", marginBottom: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}><span style={{ fontSize: 12, fontWeight: 600, color: C.tx }}>Total course progress</span><span style={{ fontSize: 14, fontWeight: 600, color: totalPct === 100 ? C.green : C.tx, fontFamily: F.mono }}>{totalPct}%</span></div>
      <div style={{ width: "100%", height: 6, background: C.bdr, borderRadius: 3, overflow: "hidden" }}><div style={{ width: `${totalPct}%`, height: "100%", background: totalPct === 100 ? C.green : C.blue, borderRadius: 3, transition: "width 0.3s" }} /></div>
      <div style={{ fontSize: 11, color: C.txS, marginTop: 4 }}>{doneTopics}/{totalTopics} topics completed across {CCA_COURSES.length} courses</div>
    </div>

    {/* Courses with sub-topics */}
    <div style={{ background: C.bgS, padding: "12px 16px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ display: "flex", justifyContent: "space-between" }}><div style={{ fontSize: 14, fontWeight: 600, color: C.tx }}>Courses</div><div style={{ fontSize: 12, color: C.txS }}>~29 hrs total</div></div></div>
    {CCA_COURSES.map(c => { const done = c.topics.filter((_, i) => topicDone[c.id + "_" + i]).length; const pct = Math.round((done / c.topics.length) * 100); const isOpen = openCourse === c.id; return (<div key={c.id}>
      <div onClick={() => setOpenCourse(isOpen ? null : c.id)} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 16px", borderBottom: `1px solid ${C.bdr}`, cursor: "pointer" }}>
        <span style={{ fontSize: 10, color: C.txT, transform: isOpen ? "rotate(90deg)" : "rotate(0)", transition: "transform 0.15s" }}>{"\u25B6"}</span>
        <div style={{ flex: 1 }}><div style={{ fontSize: 13, color: C.tx }}>{c.name}{c.core && <span style={{ fontSize: 10, fontWeight: 500, padding: "1px 6px", borderRadius: 8, background: C.redBg, color: C.red, marginLeft: 6 }}>core</span>}</div><div style={{ fontSize: 11, color: C.txT }}>{c.domain}</div></div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ fontSize: 11, fontWeight: 500, color: pct === 100 ? C.green : C.txS, fontFamily: F.mono }}>{pct}%</span>
          <div style={{ width: 40, height: 4, background: C.bdr, borderRadius: 2, overflow: "hidden" }}><div style={{ width: `${pct}%`, height: "100%", background: pct === 100 ? C.green : C.blue, borderRadius: 2 }} /></div>
          <span style={{ fontSize: 12, color: C.txS, fontFamily: F.mono, flexShrink: 0, width: 30, textAlign: "right" }}>{c.hrs}</span>
        </div>
      </div>
      {isOpen && (<div style={{ padding: "0 16px 8px 42px" }}>{c.topics.map((t, ti) => { const isDone = topicDone[c.id + "_" + ti]; return (<div key={ti} onClick={() => toggleTopic(c.id, ti)} style={{ display: "flex", alignItems: "center", gap: 8, padding: "5px 0", borderBottom: `1px solid ${C.bdr}`, cursor: "pointer" }}>
        {isDone ? <div style={{ width: 14, height: 14, borderRadius: 4, background: C.green, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}><svg width="8" height="6" viewBox="0 0 8 6" fill="none"><path d="M1 3L3 5L7 1" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" /></svg></div> : <div style={{ width: 14, height: 14, borderRadius: 4, border: `1.5px solid ${C.bdrH}`, flexShrink: 0 }} />}
        <span style={{ fontSize: 13, color: isDone ? C.txT : C.tx, textDecoration: isDone ? "line-through" : "none" }}>{t}</span>
      </div>); })}</div>)}
    </div>); })}

    {/* Links */}
    <div style={{ display: "flex", gap: 8, flexWrap: "wrap", padding: "12px 0" }}><a href="https://anthropic.skilljar.com" target="_blank" rel="noopener" style={{ ...lnk, padding: "6px 14px", border: `1px solid ${C.bdr}`, borderRadius: 4 }}>All courses</a><a href="https://anthropic.skilljar.com/claude-certified-architect-foundations-access-request" target="_blank" rel="noopener" style={{ ...lnk, padding: "6px 14px", border: `1px solid ${C.bdr}`, borderRadius: 4 }}>Request exam access</a><a href="https://claude.com/partners" target="_blank" rel="noopener" style={{ ...lnk, padding: "6px 14px", border: `1px solid ${C.bdr}`, borderRadius: 4 }}>Partner Network (free)</a></div>

    {/* Exam domains */}
    <div style={{ height: 12 }} />
    <div style={{ background: C.bgS, padding: "12px 16px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ fontSize: 14, fontWeight: 600, color: C.tx }}>5 exam domains</div></div>
    {CCA_DOMAINS.map((d, i) => <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, padding: "8px 16px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ width: 36, fontSize: 16, fontWeight: 600, color: d.color, fontFamily: F.mono, flexShrink: 0 }}>{d.weight}%</div><div style={{ flex: 1 }}><div style={{ fontSize: 13, fontWeight: 500, color: C.tx }}>{d.name}</div><div style={{ fontSize: 12, color: C.txS }}>{d.desc}</div></div></div>)}

    {/* Prep checklist */}
    <div style={{ height: 20 }} />
    <div style={{ background: C.bgS, padding: "12px 16px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ display: "flex", justifyContent: "space-between" }}><div style={{ fontSize: 14, fontWeight: 600, color: C.tx }}>Prep checklist</div><div style={{ fontSize: 12, color: donePrep === prep.length ? C.green : C.txS }}>{donePrep}/{prep.length}</div></div></div>
    {prep.map(p => <div key={p.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 16px", borderBottom: `1px solid ${C.bdr}`, cursor: "pointer" }} onClick={() => togglePrep(p.id)}>{p.done ? <div style={{ width: 14, height: 14, borderRadius: 4, background: C.green, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}><svg width="8" height="6" viewBox="0 0 8 6" fill="none"><path d="M1 3L3 5L7 1" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" /></svg></div> : <div style={{ width: 14, height: 14, borderRadius: 4, border: `1.5px solid ${C.bdrH}`, flexShrink: 0 }} />}<span style={{ fontSize: 13, color: p.done ? C.txT : C.tx, textDecoration: p.done ? "line-through" : "none" }}>{p.text}</span></div>)}

    {/* Pre-test baseline */}
    <div style={{ height: 20 }} />
    <div style={{ background: C.bgS, padding: "12px 16px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ display: "flex", justifyContent: "space-between" }}><div style={{ fontSize: 14, fontWeight: 600, color: C.tx }}>Pre-test baseline</div><div style={{ fontSize: 16, fontWeight: 600, color: C.red, fontFamily: F.mono }}>379 / 1,000</div></div></div>
    {[{ domain: "Agentic Architecture & Orchestration", weight: 27, score: "2/5", pct: 40, color: C.green }, { domain: "Prompt Engineering & Structured Output", weight: 20, score: "1/5", pct: 20, color: C.blue }, { domain: "Claude Code Config & Workflows", weight: 20, score: "2/5", pct: 40, color: C.purple }, { domain: "Tool Design & MCP Integration", weight: 18, score: "1/4", pct: 25, color: C.orange }, { domain: "Context Management & Reliability", weight: 15, score: "1/4", pct: 25, color: C.coral }].map((d, i) => <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "6px 16px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ fontSize: 12, color: C.txS, flex: 1 }}>{d.domain} ({d.weight}%)</div><div style={{ fontSize: 12, fontFamily: F.mono, color: C.txS, flexShrink: 0, width: 30, textAlign: "right" }}>{d.score}</div><div style={{ width: 60, height: 5, background: C.bgS, borderRadius: 3, overflow: "hidden", flexShrink: 0 }}><div style={{ width: `${d.pct}%`, height: "100%", background: d.pct >= 70 ? C.green : d.pct >= 50 ? C.orange : C.red, borderRadius: 3 }} /></div><div style={{ fontSize: 12, fontFamily: F.mono, color: d.pct >= 70 ? C.green : d.pct >= 50 ? C.orange : C.red, flexShrink: 0, width: 30, textAlign: "right" }}>{d.pct}%</div></div>)}
    <div style={{ padding: "8px 16px", fontSize: 11, color: C.txT }}>Target: 720+ (need ~341 point improvement)</div>

    {/* Roles */}
    <div style={{ height: 20 }} />
    <div style={{ background: C.bgS, padding: "12px 16px", borderBottom: `1px solid ${C.bdr}` }}><div style={{ fontSize: 14, fontWeight: 600, color: C.tx }}>Roles this opens</div></div>
    {["AI / Claude Solution Architect", "AI Engineer / Agentic Systems Engineer", "Forward Deployed Engineer", "AI Implementation Specialist", "Partner Delivery Architect (Accenture, Cognizant, etc.)"].map((r, i) => <div key={i} style={{ padding: "6px 16px", borderBottom: `1px solid ${C.bdr}`, fontSize: 13, color: C.tx }}>{r}</div>)}

    {/* Tip */}
    <div style={{ height: 20 }} />
    <div style={{ background: C.bgS, padding: "12px 16px", borderRadius: 4 }}><div style={{ fontSize: 12, color: C.txS, lineHeight: 1.6 }}>Tip: Anthropic recommends scoring 900+ on the Skilljar practice test (60 questions) before sitting the real exam. Someone also created a Udemy practice set with 360 questions for additional prep.</div></div>

    {/* ── Reference section (merged from old Reference tab) ── */}
    <div style={{ height: 32 }} />
    <h2 style={{ fontFamily: F.serif, fontSize: 22, fontWeight: 700, color: C.tx, margin: "0 0 16px", letterSpacing: "-0.01em" }}>Reference</h2>
    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10, marginBottom: 20 }}><div style={{ background: C.bgS, borderRadius: 4, padding: "10px 12px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", marginBottom: 3 }}>CCA skills</div><div style={{ fontSize: 13, fontWeight: 500, color: C.tx }}>{allSkillsFromPhases.length} total</div></div><div style={{ background: C.bgS, borderRadius: 4, padding: "10px 12px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", marginBottom: 3 }}>Covered by agents</div><div style={{ fontSize: 13, fontWeight: 500, color: coveredByAgents.size === allSkillsFromPhases.length ? C.green : C.orange }}>{coveredByAgents.size}/{allSkillsFromPhases.length}</div></div><div style={{ background: C.bgS, borderRadius: 4, padding: "10px 12px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", marginBottom: 3 }}>Gaps</div><div style={{ fontSize: 13, fontWeight: 500, color: uncovered.length === 0 ? C.green : C.red }}>{uncovered.length === 0 ? "None" : uncovered.length + " uncovered"}</div></div></div>
    {REF_MATRIX.map((domain, di) => <div key={di}><div style={{ background: C.bgS, padding: "12px 16px", borderTop: di === 0 ? `1px solid ${C.bdr}` : "none", borderBottom: `1px solid ${C.bdr}` }}><div style={{ display: "flex", alignItems: "baseline", gap: 8, marginBottom: 4 }}><div style={{ width: 7, height: 7, borderRadius: 4, background: domain.color, flexShrink: 0 }} /><span style={{ fontSize: 14, fontWeight: 600, color: C.tx }}>{domain.domain}</span><span style={{ fontSize: 12, fontFamily: F.mono, color: domain.color, marginLeft: "auto" }}>{domain.weight}%</span></div><div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}><Pill color={C.txS} bg={C.bgS}>{domain.phase}</Pill>{domain.courses.map((c, i) => <Pill key={i} color={C.purple} bg={C.purpleBg}>{c}</Pill>)}</div></div><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr" }}><div style={{ padding: "8px 16px 4px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", padding: "4px 0 6px" }}>Skills tested</div>{domain.skills.map(s => { const agents = agentSkillMap[s.id] || []; return <div key={s.id} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0", borderBottom: `1px solid ${C.bdr}` }}><div style={{ width: 7, height: 7, borderRadius: 4, background: agents.length > 0 ? C.green : C.red, flexShrink: 0 }} /><span style={{ fontSize: 13, fontFamily: F.sans, color: C.tx, flex: 1, lineHeight: 1.45 }}>{s.text}</span><span style={{ fontSize: 10, color: agents.length > 0 ? C.green : C.red, flexShrink: 0 }}>{agents.length > 0 ? agents.length + " agents" : "gap"}</span></div>; })}</div><div style={{ padding: "8px 16px 4px" }}><div style={{ fontSize: 10, fontWeight: 600, color: C.txT, textTransform: "uppercase", letterSpacing: "0.04em", padding: "4px 0 6px" }}>Covered by building</div>{domain.agents.map((name, i) => { const agent = AGENTS.find(a => a.name === name); return <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0", borderBottom: `1px solid ${C.bdr}` }}>{agent ? <Tag color={agent.tagColor}>{agent.name}</Tag> : <span style={{ fontSize: 13, color: C.tx }}>{name}</span>}</div>; })}</div></div>{di < REF_MATRIX.length - 1 && <div style={{ height: 12 }} />}</div>)}
    <div style={{ height: 20 }} />
    <div style={{ background: C.bgS, padding: "10px 16px", borderBottom: `1px solid ${C.bdr}` }}><span style={{ fontSize: 14, fontWeight: 600, color: C.tx }}>Full skill-to-agent map</span></div>
    {GP_PHASES.flatMap(ph => ph.skills).map(skill => { const agents = agentSkillMap[skill.id] || []; const phase = GP_PHASES.find(p => p.skills.some(s => s.id === skill.id)); return <div key={skill.id} style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 16px", borderBottom: `1px solid ${C.bdr}` }}><Tag color={phase?.color || "blue"}>{phase?.ph || "?"}</Tag><span style={{ fontSize: 13, color: C.tx, flex: 1 }}>{skill.text}</span><div style={{ display: "flex", gap: 4, flexWrap: "wrap", justifyContent: "flex-end" }}>{agents.length > 0 ? agents.map((a, i) => <span key={i} style={{ fontSize: 9, padding: "1px 6px", borderRadius: 8, background: C.greenBg, color: C.green }}>{a.replace(" Officer", "").replace(" / Astrologer", "")}</span>) : <span style={{ fontSize: 9, padding: "1px 6px", borderRadius: 8, background: C.redBg, color: C.red }}>no agent</span>}</div></div>; })}
  </div>);
}

// ── How To tab ──
function HowToTab({ howtoData, setHowtoData }) {
  const [activeGuide, setActiveGuide] = useState(null);
  const getStepDone = (guideId, stepIdx) => (howtoData[guideId]?.steps || {})[stepIdx] || false;
  const toggleStep = (guideId, stepIdx) => { setHowtoData(p => ({ ...p, [guideId]: { ...p[guideId], steps: { ...(p[guideId]?.steps || {}), [stepIdx]: !getStepDone(guideId, stepIdx) } } })); };
  return (<div>{HOWTO_GUIDES.map(g => { const done = g.steps.filter((_, i) => getStepDone(g.id, i)).length; const isOpen = activeGuide === g.id; return (<div key={g.id} style={{ marginBottom: 12 }}><div onClick={() => setActiveGuide(isOpen ? null : g.id)} style={{ padding: "12px 16px", background: C.bgS, cursor: "pointer", display: "flex", alignItems: "center", gap: 10, borderRadius: isOpen ? "4px 4px 0 0" : 4 }}><span style={{ fontSize: 10, color: C.txT, transform: isOpen ? "rotate(90deg)" : "rotate(0)", transition: "transform 0.15s" }}>{"\u25B6"}</span><span style={{ fontSize: 14, fontWeight: 600, color: C.tx, flex: 1 }}>{g.title}</span><span style={{ fontSize: 12, color: done === g.steps.length ? C.green : C.txT }}>{done}/{g.steps.length}</span><div style={{ display: "flex", gap: 4 }}>{g.skills.map((s, i) => <Pill key={i} color={C.blue} bg={C.blueBg}>{s}</Pill>)}</div></div>{isOpen && (<div><div style={{ padding: "10px 16px", fontSize: 13, color: C.txS, lineHeight: 1.6, borderBottom: `1px solid ${C.bdr}` }}>{g.context}</div>{g.steps.map((step, i) => { const done2 = getStepDone(g.id, i); return (<div key={i} style={{ borderBottom: `1px solid ${C.bdr}` }}><div style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 16px", background: done2 ? C.greenBg : "transparent" }}><div onClick={() => toggleStep(g.id, i)} style={{ width: 16, height: 16, borderRadius: 4, flexShrink: 0, cursor: "pointer", background: done2 ? C.green : "transparent", border: done2 ? "none" : `1.5px solid ${C.bdrH}`, display: "flex", alignItems: "center", justifyContent: "center" }}>{done2 && <svg width="8" height="6" viewBox="0 0 8 6" fill="none"><path d="M1 3L3 5L7 1" stroke="white" strokeWidth="1.5" strokeLinecap="round" /></svg>}</div><span style={{ fontSize: 14, fontWeight: 600, color: done2 ? C.green : C.tx }}>{step.step}</span></div><div style={{ display: "grid", gridTemplateColumns: "1fr 280px", gap: 16, padding: "8px 16px 12px 42px" }}><div><div style={{ fontSize: 13, color: C.tx, lineHeight: 1.7 }}>{step.what.split("\n").map((line, li) => { const renderBold = text => { const parts = text.split(/\*\*(.*?)\*\*/g); return parts.map((p, pi) => pi % 2 === 1 ? <strong key={pi} style={{ fontWeight: 600 }}>{p}</strong> : p); }; if (line.startsWith("> ")) return <div key={li} style={{ display: "flex", gap: 6, alignItems: "flex-start", padding: "2px 0" }}><span style={{ color: C.blue, flexShrink: 0 }}>{"\u2192"}</span><span>{renderBold(line.slice(2))}</span></div>; if (line.trim() === "") return <div key={li} style={{ height: 6 }} />; return <div key={li}>{renderBold(line)}</div>; })}</div></div><div style={{ background: C.blueBg, borderRadius: 4, padding: "10px 12px" }}><div style={{ fontSize: 12, color: C.txS, lineHeight: 1.7 }}>{step.why}</div></div></div></div>); })}</div>)}</div>); })}</div>);
}

// ── Notes tab (simple notebook with lines) ──
function NotesTab({ notes, setNotes }) {
  const addLine = () => setNotes(p => [...p, ""]);
  const updateLine = (idx, val) => setNotes(p => p.map((n, i) => i === idx ? val : n));
  const removeLine = (idx) => { if (notes.length > 1) setNotes(p => p.filter((_, i) => i !== idx)); };
  useEffect(() => { if (notes.length === 0) setNotes([""]); }, []);
  return (<div>
    <div style={{ border: `1px solid ${C.bdr}`, borderRadius: 4, background: C.bg }}>
      {notes.map((line, i) => (
        <div key={i} style={{ display: "flex", borderBottom: `1px solid ${C.bdr}`, minHeight: 36 }}>
          <div style={{ width: 36, display: "flex", alignItems: "flex-start", justifyContent: "center", paddingTop: 10, color: C.txT, fontSize: 11, fontFamily: F.mono, flexShrink: 0, background: C.bgS, borderRight: `1px solid ${C.bdr}` }}>{i + 1}</div>
          <textarea value={line} onChange={e => updateLine(i, e.target.value)} onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); const newNotes = [...notes]; newNotes.splice(i + 1, 0, ""); setNotes(newNotes); setTimeout(() => { const next = document.querySelector(`[data-line="${i + 1}"]`); if (next) next.focus(); }, 50); } }} data-line={i} rows={1} style={{ flex: 1, border: "none", outline: "none", padding: "8px 12px", fontFamily: F.sans, fontSize: 14, color: C.tx, lineHeight: 1.6, resize: "none", background: "transparent", overflow: "hidden", minHeight: 36 }} ref={el => { if (el) { el.style.height = "auto"; el.style.height = Math.max(36, el.scrollHeight) + "px"; } }} />
          {notes.length > 1 && <div onClick={() => removeLine(i)} style={{ width: 28, display: "flex", alignItems: "flex-start", justifyContent: "center", paddingTop: 10, cursor: "pointer", color: C.txT, fontSize: 12, flexShrink: 0, opacity: 0.5 }} onMouseEnter={e => e.target.style.opacity = 1} onMouseLeave={e => e.target.style.opacity = 0.5}>{"\u00D7"}</div>}
        </div>
      ))}
    </div>
    <button onClick={addLine} style={{ marginTop: 8, padding: "6px 16px", borderRadius: 4, border: `1px solid ${C.bdr}`, background: C.bgS, fontSize: 13, fontFamily: F.sans, color: C.txS, cursor: "pointer", display: "flex", alignItems: "center", gap: 4 }}>+ Add line</button>
  </div>);
}

// ── Main App ──
export default function App() {
  const [tab, setTab] = useState("product");
  const [startDate, setStartDate] = useState(null);
  const [data, setData] = useState({});
  const [agentData, setAgentData] = useState({});
  const [notes, setNotes] = useState([""]);
  const [ccaData, setCcaData] = useState({});
  const [howtoData, setHowtoData] = useState({});
  const [loaded, setLoaded] = useState(false);
  const saveGuard = useRef(false);
  useEffect(() => { (async () => { try { const r = await osLoad("start", null); setStartDate(r); } catch (e) {} try { const r = await osLoad("data", {}); setData(r); } catch (e) {} try { const r = await osLoad("agents", {}); setAgentData(r); } catch (e) {} try { const r = await osLoad("notes", [""]); if (r && Array.isArray(r) && r.length > 0) setNotes(r); } catch (e) {} try { const r = await osLoad("cca", {}); setCcaData(r); } catch (e) {} try { const r = await osLoad("howto", {}); setHowtoData(r); } catch (e) {} setLoaded(true); setTimeout(() => { saveGuard.current = true; }, 500); })(); }, []);
  useEffect(() => { if (!loaded || !saveGuard.current) return; const doSave = async () => { try { await osSave("start", startDate); } catch (e) {} try { await osSave("data", data); } catch (e) {} try { await osSave("agents", agentData); } catch (e) {} try { await osSave("notes", notes); } catch (e) {} try { await osSave("cca", ccaData); } catch (e) {} try { await osSave("howto", howtoData); } catch (e) {} }; doSave(); }, [startDate, data, agentData, notes, ccaData, howtoData, loaded]);
  const tabs = [{ k: "product", l: "Product" }, { k: "learn", l: "Plan" }, { k: "cca", l: "CCA" }, { k: "howto", l: "How to" }, { k: "notes", l: "Notes" }];
  return (<div style={{ minHeight: "100vh", background: C.bg, color: C.tx }}><div style={{ maxWidth: 900, margin: "0 auto", padding: "32px 48px 60px" }}>
    <h1 style={{ fontFamily: F.serif, fontSize: 36, fontWeight: 700, color: C.tx, margin: 0, letterSpacing: "-0.02em", lineHeight: 1.2 }}>Growth Path</h1>
    <p style={{ fontFamily: F.sans, fontSize: 14, color: C.txS, margin: "4px 0 16px", lineHeight: 1.6 }}>Becoming an AI Implementation Specialist</p>
    <div style={{ display: "flex", gap: 0, borderBottom: `1px solid ${C.bdr}`, marginBottom: 20 }}>{tabs.map((t, i) => <button key={t.k} onClick={() => setTab(t.k)} style={{ padding: `8px 16px 8px ${i === 0 ? 0 : 16}px`, border: "none", background: "none", fontFamily: F.sans, fontSize: 14, fontWeight: tab === t.k ? 600 : 400, color: tab === t.k ? C.tx : C.txT, cursor: "pointer", borderBottom: tab === t.k ? `2px solid ${C.tx}` : "2px solid transparent", marginBottom: -1 }}>{t.l}</button>)}</div>
    {tab === "product" && <ProductTab agentData={agentData} setAgentData={setAgentData} data={data} setData={setData} />}
    {tab === "learn" && <PlanTab startDate={startDate} setStartDate={setStartDate} data={data} setData={setData} />}
    {tab === "cca" && <CCATab ccaData={ccaData} setCcaData={setCcaData} />}
    {tab === "howto" && <HowToTab howtoData={howtoData} setHowtoData={setHowtoData} />}
    {tab === "notes" && <NotesTab notes={notes} setNotes={setNotes} />}
  </div></div>);
}
